export async function seedWhatWeb() {
    try {
        console.log("Seeding tool WhatWeb...");
        await Tool.deleteMany({ name: "WhatWeb" });
        
        const toolDoc = new Tool(toolPayload);
        await toolDoc.save();
        
        console.log("Seeded tool WhatWeb successfully.");
    } catch (error) {
        console.error("Seeding tool WhatWeb failed:", error);
        throw error;
    }
}
